1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const ALIKE_BUNDLE_DISCOUNT = 15;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	function ceilToWholeGold(amount: number): number {
16	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
17	}
18	
19	function basePremiumFor(itemType: string): number {
20	  return BASE_PREMIUMS[itemType] ?? 0;
21	}
22	
23	function countOfType(items: Array<{ type: string }>, itemType: string): number {
24	  return items.filter((item) => item.type === itemType).length;
25	}
26	
27	function alikeBundleDiscount(items: Array<{ type: string }>): number {
28	  return [...COMPONENT_TYPES]
29	    .reduce((sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3), 0)
30	    * ALIKE_BUNDLE_DISCOUNT;
31	}
32	
33	export function quote(input: { items: Array<{ type: string }> }): number {
34	  const basePremiumSum = input.items.reduce((sum, item) => sum + basePremiumFor(item.type), 0);
35	  const itemsTotal = basePremiumSum - alikeBundleDiscount(input.items);
36	  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
37	  return ceilToWholeGold(total);
38	}
39	
40	export function claim(_input: unknown): number {
41	  return undefined as unknown as number;
42	}
